def process_payment(user, cart_items, payment_details):
    # Define discount rates based on user roles
    discount_rates = {
        'enterprise': 0.30,
        'premium': 0.15,
        'basic': 0.00
    }
    
    # Calculate total cart value
    cart_total = sum(item['price'] * item['quantity'] for item in cart_items)
    
    # Apply discount based on user role
    if user.role in discount_rates:
        discount_amount = cart_total * discount_rates[user.role]
        final_total = cart_total - discount_amount
    else:
        raise ValueError("Invalid user role")
    
    # Process payment (simplified example)
    print(f"Processing payment for {user.role} user with total: ${final_total}")
    print(f"Payment details: {payment_details}")
    
    return final_total

